//! Code emitters: turn the surface registry into backend source, type stubs,
//! a JSON schema, and package scaffolds. Each milestone registers more emitters
//! in `render_all`; the function stays pure (no filesystem access) so it can be
//! diffed by the drift guard.

use crate::bind::{Kind, Privilege, Symbol, SURFACE};
use std::collections::BTreeMap;

const HEADER: &str = "// DO NOT EDIT — generated by autoagent-bingen from bind.rs.\n";

/// Every generated file as `relative_path -> content`. Pure: no I/O.
pub fn render_all() -> BTreeMap<String, String> {
    let mut m = BTreeMap::new();
    m.insert("src/node/napi.rs".into(), napi_backend());
    m.insert("dist/index.d.ts".into(), dts());
    m.insert("schema/surface.schema.json".into(), schema_json());
    m
}

// ---------------------------------------------------------------------------
// Shared helpers.
// ---------------------------------------------------------------------------

fn priv_str(p: Privilege) -> &'static str {
    match p {
        Privilege::Read => "read",
        Privilege::Mutate => "mutate",
    }
}

fn kind_str(k: Kind) -> &'static str {
    match k {
        Kind::Sync => "sync",
        Kind::Async => "async",
    }
}

/// snake_case -> camelCase (JS/TS naming for the exported functions).
fn camel(snake: &str) -> String {
    let mut out = String::new();
    let mut up = false;
    for c in snake.chars() {
        if c == '_' {
            up = true;
        } else if up {
            out.extend(c.to_uppercase());
            up = false;
        } else {
            out.push(c);
        }
    }
    out
}

// ---------------------------------------------------------------------------
// JSON schema of the surface (FR-11).
// ---------------------------------------------------------------------------

fn schema_json() -> String {
    let syms: Vec<String> = SURFACE
        .iter()
        .map(|s| {
            let args: Vec<String> = s
                .args
                .iter()
                .map(|a| format!("{{ \"name\": \"{}\", \"type\": \"{}\" }}", a.name, a.ty))
                .collect();
            format!(
                "    {{ \"name\": \"{}\", \"kind\": \"{}\", \"privilege\": \"{}\", \"args\": [{}], \"returns\": \"{}\" }}",
                s.name,
                kind_str(s.kind),
                priv_str(s.privilege),
                args.join(", "),
                s.returns
            )
        })
        .collect();
    format!(
        "{{\n  \"version\": \"1.0.0\",\n  \"symbols\": [\n{}\n  ]\n}}\n",
        syms.join(",\n")
    )
}

// ---------------------------------------------------------------------------
// TypeScript stubs (.d.ts), shared by Node and Deno (FR-9).
// ---------------------------------------------------------------------------

fn dts() -> String {
    let mut out = String::from("// DO NOT EDIT — generated by autoagent-bingen.\n");
    out.push_str(
        "export class AutoAgentError extends Error { code: string; exitCode: number; }\n",
    );
    for s in SURFACE {
        let params: Vec<String> = s
            .args
            .iter()
            .map(|a| format!("{}: {}", a.name, a.ty))
            .collect();
        let ret = s.returns.to_string();
        let ret = if matches!(s.kind, Kind::Async) {
            format!("Promise<{ret}>")
        } else {
            ret
        };
        out.push_str(&format!(
            "/** {} */\nexport function {}({}): {};\n",
            s.doc,
            camel(s.name),
            params.join(", "),
            ret
        ));
    }
    out
}

// ---------------------------------------------------------------------------
// napi-rs backend (Node primary). B1 emits the read surface; mutating + async
// symbols are added in B3-T3.
// ---------------------------------------------------------------------------

const NAPI_GLUE: &str = r#"use napi_derive::napi;
use crate::bind;

fn to_napi(e: bind::BindError) -> napi::Error {
    napi::Error::new(
        napi::Status::GenericFailure,
        format!("[{}|{}] {}", e.code, e.exit_code, e.message),
    )
}

fn parse(j: String) -> napi::Result<serde_json::Value> {
    serde_json::from_str(&j).map_err(|e| napi::Error::from_reason(e.to_string()))
}

"#;

fn napi_backend() -> String {
    let mut out = String::from(HEADER);
    out.push_str(NAPI_GLUE);
    for s in SURFACE {
        out.push_str(&napi_fn(s));
    }
    out
}

/// Emit one napi function. B1 covers the synchronous read surface; the
/// remaining symbols are emitted in later milestones (their arms return an
/// empty string here so the generated file stays minimal and valid).
fn napi_fn(s: &Symbol) -> String {
    match s.name {
        "version" => "#[napi]\npub fn version() -> napi::Result<u32> {\n    bind::version()\n        .map(|v| v.trim().parse().unwrap_or(0))\n        .map_err(to_napi)\n}\n\n".into(),
        "doctor" => napi_read_value("doctor", "DoctorReport"),
        "analyze" => napi_read_value("analyze", "ProjectAnalysis"),
        _ => String::new(),
    }
}

/// A read symbol that takes `root: string` and returns a typed JS object.
fn napi_read_value(name: &str, ts_ty: &str) -> String {
    format!(
        "#[napi(ts_return_type = \"{ts_ty}\")]\npub fn {name}(root: String) -> napi::Result<serde_json::Value> {{\n    let j = bind::{name}(&root).map_err(to_napi)?;\n    parse(j)\n}}\n\n"
    )
}
